import{_ as e,o as a,c as d,ag as i}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"状态流转图","description":"","frontmatter":{},"headers":[],"relativePath":"workflows/state-machines.md","filePath":"workflows/state-machines.md"}'),r={name:"workflows/state-machines.md"};function o(n,t,s,l,p,c){return a(),d("div",null,[...t[0]||(t[0]=[i(`<h1 id="状态流转图" tabindex="-1">状态流转图 <a class="header-anchor" href="#状态流转图" aria-label="Permalink to &quot;状态流转图&quot;">​</a></h1><p><strong>一句话理解：每一步都必须留下清晰的证据，半成品会被挡在门外。</strong></p><hr><h2 id="为什么要有状态" tabindex="-1">为什么要有状态 <a class="header-anchor" href="#为什么要有状态" aria-label="Permalink to &quot;为什么要有状态&quot;">​</a></h2><p>你可能想问：「不就是写一篇笔记吗？为什么要搞这么复杂，又是状态又是 Gate 的？」</p><p>让我告诉你为什么。</p><p>真实的运营团队经常遇到这种情况：</p><ul><li>「那个热点文章写好了吗？」 <ul><li>「还没，只有个开头」</li></ul></li><li>「今天的发布包呢？」 <ul><li>「还在改，上午再说」</li></ul></li><li>「上周那个系列第二篇呢？」 <ul><li>「卡住了，不知道该怎么写」</li></ul></li></ul><p>半成品在各个阶段流动，导致交付永远不确定。</p><p><strong>XHSOps 的状态机就是为了解决这个问题。</strong></p><p>它会检查三件事：</p><ol><li><strong>brand 是否 ready</strong> —— 创作之前，你的账号定位必须填完</li><li><strong>artifact 是否完整</strong> —— 上一步的产出必须完整，不能有半成品</li><li><strong>是否还有 <code>&lt;placeholder&gt;</code></strong> —— 没填完的地方不能往下走</li></ol><p>每一步都必须有产出，每一步都必须有证据。这就是为什么你会感觉「被挡住了」——其实是被保护了。</p><hr><h2 id="三种工作流的状态对比" tabindex="-1">三种工作流的状态对比 <a class="header-anchor" href="#三种工作流的状态对比" aria-label="Permalink to &quot;三种工作流的状态对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>步骤</th><th>Quick</th><th>Trend</th><th>Campaign</th></tr></thead><tbody><tr><td>起点</td><td>initialized</td><td>initialized</td><td>initialized</td></tr><tr><td>第二步</td><td>drafting</td><td>fit-checking</td><td>planned</td></tr><tr><td>第三步</td><td>reviewed</td><td>fit-approved / fit-rejected</td><td>briefing</td></tr><tr><td>第四步</td><td>iterating / done</td><td>drafting</td><td>drafting</td></tr><tr><td>第五步</td><td>done</td><td>reviewed</td><td>reviewing / iterating</td></tr><tr><td>第六步</td><td>archived</td><td>done</td><td>ready</td></tr><tr><td>第七步</td><td>-</td><td>archived</td><td>archived</td></tr></tbody></table><hr><h2 id="每个状态的含义" tabindex="-1">每个状态的含义 <a class="header-anchor" href="#每个状态的含义" aria-label="Permalink to &quot;每个状态的含义&quot;">​</a></h2><h3 id="quick-状态" tabindex="-1">Quick 状态 <a class="header-anchor" href="#quick-状态" aria-label="Permalink to &quot;Quick 状态&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状态</th><th>意味着什么</th></tr></thead><tbody><tr><td><code>initialized</code></td><td>选题已创建，brief 正在形成</td></tr><tr><td><code>drafting</code></td><td>初稿已经生成，等待审核</td></tr><tr><td><code>reviewed</code></td><td>审核意见已经给出</td></tr><tr><td><code>iterating</code></td><td>正在根据审核意见改写</td></tr><tr><td><code>done</code></td><td>发布包已经生成</td></tr><tr><td><code>archived</code></td><td>经验已经沉淀到知识库</td></tr></tbody></table><h3 id="trend-状态" tabindex="-1">Trend 状态 <a class="header-anchor" href="#trend-状态" aria-label="Permalink to &quot;Trend 状态&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状态</th><th>意味着什么</th></tr></thead><tbody><tr><td><code>initialized</code></td><td>热点已创建，trend-brief 正在形成</td></tr><tr><td><code>fit-checking</code></td><td>正在判断热点与品牌是否匹配</td></tr><tr><td><code>fit-approved</code></td><td>允许进入草稿阶段</td></tr><tr><td><code>fit-rejected</code></td><td>热点被放弃，但判断过程值得归档</td></tr><tr><td><code>drafting</code></td><td>初稿正在撰写</td></tr><tr><td><code>reviewed</code></td><td>审核意见已经给出</td></tr><tr><td><code>done</code></td><td>发布包已经生成</td></tr><tr><td><code>archived</code></td><td>经验已经沉淀到知识库</td></tr></tbody></table><h3 id="campaign-状态" tabindex="-1">Campaign 状态 <a class="header-anchor" href="#campaign-状态" aria-label="Permalink to &quot;Campaign 状态&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状态</th><th>意味着什么</th></tr></thead><tbody><tr><td><code>initialized</code></td><td>campaign 已创建</td></tr><tr><td><code>planned</code></td><td>proposal 已生成，规划已完成</td></tr><tr><td><code>briefing</code></td><td>campaign brief 和 tasks 正在形成</td></tr><tr><td><code>drafting</code></td><td>至少有一篇 note 进入写作</td></tr><tr><td><code>reviewing</code></td><td>审核中（至少一篇 note 在审核）</td></tr><tr><td><code>iterating</code></td><td>改写中（至少一篇 note 在改写）</td></tr><tr><td><code>ready</code></td><td>所有笔记完成审核，可以发布</td></tr><tr><td><code>archived</code></td><td>campaign 经验已经沉淀</td></tr></tbody></table><hr><h2 id="最常见的-4-个拦截点" tabindex="-1">最常见的 4 个拦截点 <a class="header-anchor" href="#最常见的-4-个拦截点" aria-label="Permalink to &quot;最常见的 4 个拦截点&quot;">​</a></h2><p>XHSOps 有 4 个最常见的 Gate，也就是你会「被挡住」的地方。让我解释一下为什么这些 Gate 是必要的。</p><h3 id="gate-1-brand-没完成就想创作" tabindex="-1">Gate 1：brand 没完成就想创作 <a class="header-anchor" href="#gate-1-brand-没完成就想创作" aria-label="Permalink to &quot;Gate 1：brand 没完成就想创作&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ brand ready → quick / hot / plan</span></span></code></pre></div><p>报错信息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cannot start content creation because brand positioning is incomplete</span></span></code></pre></div><p><strong>这是在保护你：</strong></p><p>如果你还没想清楚自己的账号定位是什么，你写出来的内容会没有一致性。这次写 AI 效率，下次写美妆，后天写职场——读者会困惑：「这个账号到底是干嘛的？」</p><p>Brand 是创作的基础。就像盖房子要打地基一样，brand 就是你内容的地基。</p><p><strong>解决方案</strong>：运行 <code>xhsops doctor</code> 看看 brand 哪里没填完。</p><hr><h3 id="gate-2-草稿没写完就想审核" tabindex="-1">Gate 2：草稿没写完就想审核 <a class="header-anchor" href="#gate-2-草稿没写完就想审核" aria-label="Permalink to &quot;Gate 2：草稿没写完就想审核&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ drafting → reviewed</span></span></code></pre></div><p>报错信息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cannot proceed to review because the previous artifact is incomplete</span></span></code></pre></div><p><strong>这是在保护你：</strong></p><p>审核是一个「检查产出」的动作。如果草稿还是半成品（比如还有 <code>&lt;placeholder&gt;</code> 没填完），审核就没有意义——你审核的是一团浆糊，不是一篇稿子。</p><p>而且，审核意见是会给 AI 用的。如果草稿本身就是乱的，AI 收到的指令也是乱的，改写出来的内容只会更乱。</p><p><strong>解决方案</strong>：先把草稿写完，确保没有 <code>&lt;placeholder&gt;</code>。</p><hr><h3 id="gate-3-审核没完成就想改写" tabindex="-1">Gate 3：审核没完成就想改写 <a class="header-anchor" href="#gate-3-审核没完成就想改写" aria-label="Permalink to &quot;Gate 3：审核没完成就想改写&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ reviewed → iterating</span></span></code></pre></div><p>报错信息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cannot proceed to rewrite because review has not been completed</span></span></code></pre></div><p><strong>这是在保护你：</strong></p><p>改写是需要方向的。审核意见就是方向。</p><p>如果没有审核意见，AI 怎么知道改哪里？让它「随便改改」的结果通常是「改得面目全非」。</p><p>审核是一个「人类判断」的过程。你得先告诉 AI 哪里有问题、问题是什么，AI 才能针对性地改。</p><p><strong>解决方案</strong>：认真写审核意见，这是在帮你打磨内容。</p><hr><h3 id="gate-4-终稿或审核没完成就想发布" tabindex="-1">Gate 4：终稿或审核没完成就想发布 <a class="header-anchor" href="#gate-4-终稿或审核没完成就想发布" aria-label="Permalink to &quot;Gate 4：终稿或审核没完成就想发布&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ reviewed → done</span></span>
<span class="line"><span>❌ reviewing → ready</span></span></code></pre></div><p>报错信息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cannot proceed to publish because review/final draft is incomplete</span></span></code></pre></div><p><strong>这是在保护你：</strong></p><p>这是最重要的一个 Gate。</p><p>很多工具做到「有一篇终稿」就停了。但真实运营里，终稿只是进入了发布的门口，后面还有一堆事。</p><p>如果你把半成品发出去：</p><ul><li>读者看到的是不完整的内容</li><li>你的专业形象会受损</li><li>运营同事会问你「这个怎么发」，你答不上来</li></ul><p>Publish 需要终稿和审核都完成，这样 AI 才能生成完整的发布包。</p><p><strong>解决方案</strong>：终稿和审核都必须完成，才能生成发布包。</p><hr><h2 id="为什么这些-gate-是保护而不是麻烦" tabindex="-1">为什么这些 Gate 是保护而不是麻烦 <a class="header-anchor" href="#为什么这些-gate-是保护而不是麻烦" aria-label="Permalink to &quot;为什么这些 Gate 是保护而不是麻烦&quot;">​</a></h2><p>我知道你可能觉得这些 Gate 很烦人。</p><blockquote><p>「我就是想写个笔记，为什么要填这填那的？」</p></blockquote><blockquote><p>「我就是想发个热点，为什么要审核来审核去的？」</p></blockquote><p>让我换一个角度告诉你：</p><p><strong>Gate 不是在阻止你，而是在确保你真的在做有价值的事。</strong></p><p>没有 Gate 的创作流程是这样的：</p><ol><li>想写 → 开始写</li><li>写了 → 发出去</li><li>发了 → 不知道效果怎么样</li><li>效果不好 → 不知道原因</li></ol><p>有 Gate 的创作流程是这样的：</p><ol><li>brand 填完 → 开始写</li><li>草稿写完 → 审核</li><li>审核改写 → 定稿</li><li>定稿发布 → 归档</li><li>归档复盘 → 下次更好</li></ol><p>每一步都有产出，每一步都有证据。</p><p>这不是在增加步骤，而是在<strong>确保每一步都有价值</strong>。</p><hr><h2 id="状态机的设计原则" tabindex="-1">状态机的设计原则 <a class="header-anchor" href="#状态机的设计原则" aria-label="Permalink to &quot;状态机的设计原则&quot;">​</a></h2><p>XHSOps 的状态机遵循几个设计原则：</p><ol><li><strong>不可跳跃</strong>：你不能从 drafting 直接跳到 done，必须经过 reviewed</li><li><strong>不可逆流</strong>：你不能从 done 回到 drafting，已发布的内容不能重写</li><li><strong>必须归档</strong>：每一次创作（无论成功还是失败）都要归档，经验要沉淀</li><li><strong>Gate 必须过</strong>：每个 Gate 都是一道门槛，跨不过去就不能往下走</li></ol><p>这些原则确保了你的创作过程是可追溯、可复盘、可优化的。</p><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>状态机不是限制你，而是保护你。</p><ul><li>它确保你不会在 brand 还没想清楚时就乱写</li><li>它确保你不会把半成品带入审核</li><li>它确保你不会在没审核的情况下去改写</li><li>它确保你不会把不完整的内容发出去</li></ul><p>每一步都有产出，每一步都有证据。</p><p>这就是为什么你会感觉「被挡住了」——其实是被保护了。</p>`,90)])])}const b=e(r,[["render",o]]);export{g as __pageData,b as default};
